100→### Task 1: Shared Auth Utility (`wt-infra`)
101→
102→**Files:**
103→- Create: `_infrastructure/auth/resolve-env.mjs`
104→
105→Use @plugin-dev:plugin-structure for CLI/infrastructure scaffolding.
106→
107→- [ ] **Step 1: Create resolve-env.mjs**
108→
109→Write to `_infrastructure/auth/resolve-env.mjs`:
110→
111→```javascript
112→#!/usr/bin/env node
113→/**
114→ * Shared .env resolution utility.
115→ * Used by notion-tool.mjs and late-tool.mjs.
116→ *
117→ * Usage:
118→ *   import { resolveKey, maskKey } from './resolve-env.mjs';
119→ *   const key = resolveKey('LATE_API_KEY', { prefix: 'sk_', prefixLabel: 'Late.dev' });
120→ */
121→
122→import { readFileSync, statSync } from 'fs';
123→import { resolve, dirname } from 'path';
124→
125→/**
126→ * Walk up directories looking for .env file (max 5 levels).
127→ * Strips surrounding single/double quotes from values.
128→ */
129→function findEnvFile(startDir, maxDepth = 5) {
130→  let dir = startDir;
131→  for (let i = 0; i < maxDepth; i++) {
132→    const envPath = resolve(dir, '.env');
133→    try {
134→      const stat = statSync(envPath);
135→      if (stat.isFile()) {
136→        // Warn on overly permissive permissions (not 600 or 400)
137→        const mode = stat.mode & 0o777;
138→        if (mode !== 0o600 && mode !== 0o400) {
139→          console.error(`Warning: ${envPath} has permissive permissions (${mode.toString(8)}). Recommend chmod 600.`);
140→        }
141→        return envPath;
142→      }
143→    } catch {
144→      // File not found, continue walking up
145→    }
146→    const parent = dirname(dir);
147→    if (parent === dir) break; // Hit filesystem root
148→    dir = parent;
149→  }
150→  return null;
151→}
152→
153→/**
154→ * Parse .env file, stripping quotes from values.
155→ */
156→function parseEnvFile(filePath) {
157→  const content = readFileSync(filePath, 'utf-8');
158→  const vars = {};
159→  for (const line of content.split('\n')) {
160→    const trimmed = line.trim();
161→    if (!trimmed || trimmed.startsWith('#')) continue;
162→    const eqIndex = trimmed.indexOf('=');
163→    if (eqIndex === -1) continue;
164→    const key = trimmed.slice(0, eqIndex).trim();
165→    let value = trimmed.slice(eqIndex + 1).trim();
166→    // Strip surrounding quotes
167→    if ((value.startsWith('"') && value.endsWith('"')) ||
168→        (value.startsWith("'") && value.endsWith("'"))) {
169→      value = value.slice(1, -1);
170→    }
171→    vars[key] = value;
172→  }
173→  return vars;
174→}
175→
176→/**
177→ * Resolve an API key from environment variable or .env file.
178→ * @param {string} envVar - Environment variable name (e.g., 'LATE_API_KEY')
179→ * @param {object} opts - Options
180→ * @param {string} opts.prefix - Expected key prefix (e.g., 'sk_')
181→ * @param {string} opts.prefixLabel - Human-readable label (e.g., 'Late.dev')
182→ * @returns {string} The resolved API key
183→ * @throws {Error} If key not found or format invalid
184→ */
185→export function resolveKey(envVar, { prefix, prefixLabel } = {}) {
186→  // 1. Check environment variable
187→  let key = process.env[envVar];
188→
189→  // 2. Fall back to .env file
190→  if (!key) {
191→    const envPath = findEnvFile(process.cwd());
192→    if (envPath) {
193→      const vars = parseEnvFile(envPath);
194→      key = vars[envVar];
195→    }
196→  }
197→
198→  if (!key) {
199→    throw new Error(
200→      `${envVar} not found. Set it in your environment or .env file.\n` +
201→      `  export ${envVar}="your_key_here"`
202→    );
203→  }
204→
205→  // 3. Validate prefix if specified
206→  if (prefix && !key.startsWith(prefix)) {
207→    throw new Error(
208→      `${envVar} must start with "${prefix}" (${prefixLabel || 'API'} key format).`
209→    );
210→  }
211→
212→  // 4. Validate key format (prefix + 64 hex characters)
213→  if (prefix) {
214→    const hexPart = key.slice(prefix.length);
215→    if (hexPart.length !== 64 || !/^[a-f0-9]+$/i.test(hexPart)) {
216→      throw new Error(
217→        `${envVar} format invalid. Expected ${prefix}<64 hex characters>.`
218→      );
219→    }
220→  }
221→
222→  return key;
223→}
224→
225→/**
226→ * Mask an API key for safe display.
227→ * @param {string} key - The API key
228→ * @param {number} showLast - Number of trailing characters to show (default: 4)
229→ * @returns {string} Masked key (e.g., "sk_****...ab12")
230→ */
231→export function maskKey(key, showLast = 4) {
232→  if (!key || key.length <= showLast + 4) return '****';
233→  const prefix = key.slice(0, key.indexOf('_') + 1) || '';
234→  const suffix = key.slice(-showLast);
235→  return `${prefix}****...${suffix}`;
236→}
237→```
