253→### Task 2: Late.dev CLI Wrapper (`wt-infra`)
254→
255→**Files:**
256→- Create: `scripts/late-tool.mjs`
257→- Modify: `.gitignore` (add `.late/`)
258→
259→Use @plugin-dev:plugin-structure for CLI scaffolding.
260→
261→- [ ] **Step 1: Create late-tool.mjs**
262→
263→Write to `scripts/late-tool.mjs`. This mirrors the structure of `scripts/notion-tool.mjs`. The CLI wraps the Late.dev REST API (`https://getlate.dev/api/v1`).
264→
265→```javascript
266→#!/usr/bin/env node
267→/**
268→ * Late.dev CLI wrapper for social media publishing.
269→ * Mirrors notion-tool.mjs patterns.
270→ *
271→ * Usage: node scripts/late-tool.mjs <command> <subcommand> [options]
272→ *
273→ * Commands:
274→ *   profiles list|create
275→ *   accounts list|health|connect|disconnect
276→ *   media presign
277→ *   posts create|list|status|retry
278→ *   analytics get
279→ *   queue list|add|remove
280→ *   webhooks get|set
281→ *   --diagnostic    Test auth + list profiles/accounts
282→ *   --validate-only Lightweight auth check (CI/CD)
283→ */
284→
285→import { resolveKey, maskKey } from '../_infrastructure/auth/resolve-env.mjs';
286→
287→const BASE_URL = 'https://getlate.dev/api/v1';
288→const MAX_RETRIES = 3;
289→const RETRY_DELAYS = [1000, 2000, 4000]; // Exponential backoff
290→
291→// --- Auth ---
292→
293→function getApiKey() {
294→  return resolveKey('LATE_API_KEY', { prefix: 'sk_', prefixLabel: 'Late.dev' });
295→}
296→
297→// --- HTTP Client ---
298→
299→async function apiCall(method, path, body = null, retryCount = 0) {
300→  const apiKey = getApiKey();
301→  const maskedKey = maskKey(apiKey);
302→  const url = `${BASE_URL}${path}`;
303→
304→  // Validate HTTPS
305→  if (!url.startsWith('https://')) {
306→    throw new Error('API calls must use HTTPS');
307→  }
308→
309→  const headers = {
310→    'Authorization': `Bearer ${apiKey}`,
311→    'Content-Type': 'application/json',
312→    'Accept': 'application/json',
313→  };
314→
315→  const options = { method, headers };
316→  if (body && method !== 'GET') {
317→    options.body = JSON.stringify(body);
318→  }
319→
320→  let response;
321→  try {
322→    response = await fetch(url, options);
323→  } catch (err) {
324→    if (retryCount < MAX_RETRIES) {
325→      await sleep(RETRY_DELAYS[retryCount]);
326→      return apiCall(method, path, body, retryCount + 1);
327→    }
328→    throw Object.assign(new Error('Network error'), { code: 'LATE_NETWORK_ERROR' });
329→  }
330→
331→  // Handle errors
332→  if (!response.ok) {
333→    if (response.status === 401) {
334→      throw Object.assign(
335→        new Error(`Authentication failed. Verify your LATE_API_KEY (${maskedKey})`),
336→        { code: 'LATE_AUTH_FAILED' }
337→      );
338→    }
339→    if (response.status === 429 && retryCount < MAX_RETRIES) {
340→      const retryAfter = response.headers.get('retry-after');
341→      const delay = retryAfter ? parseInt(retryAfter) * 1000 : RETRY_DELAYS[retryCount];
342→      await sleep(delay);
343→      return apiCall(method, path, body, retryCount + 1);
344→    }
345→    if (response.status >= 500 && retryCount < MAX_RETRIES) {
346→      await sleep(RETRY_DELAYS[retryCount]);
347→      return apiCall(method, path, body, retryCount + 1);
348→    }
349→
350→    // Sanitize error body — strip reflected input
351→    let errorBody = '';
352→    try {
353→      const raw = await response.text();
354→      errorBody = raw.replace(/sk_[a-f0-9]+/gi, '[REDACTED]').slice(0, 500);
355→    } catch { /* ignore */ }
356→
357→    const code = response.status === 404 ? 'LATE_NOT_FOUND'
358→      : response.status === 429 ? 'LATE_RATE_LIMIT'
359→      : response.status >= 500 ? 'LATE_SERVER_ERROR'
360→      : 'LATE_PLATFORM_ERROR';
361→
362→    throw Object.assign(new Error(`API error ${response.status}: ${errorBody}`), { code });
363→  }
364→
365→  return response.json();
366→}
367→
368→function sleep(ms) {
369→  return new Promise(r => setTimeout(r, ms));
370→}
371→
372→// --- Subcommands ---
373→
374→const commands = {
375→  profiles: {
376→    list: () => apiCall('GET', '/profiles'),
377→    create: (args) => apiCall('POST', '/profiles', { name: args['--name'] }),
378→  },
379→  accounts: {
380→    list: (args) => apiCall('GET', `/accounts${args['--profile'] ? `?profileId=${args['--profile']}` : ''}`),
381→    health: (args) => apiCall('GET', `/accounts/${args['--account-id']}/health`),
382→    connect: (args) => apiCall('POST', '/accounts/connect', {
383→      platform: args['--platform'],
384→      profileId: args['--profile'],
385→    }),
386→    disconnect: (args) => apiCall('DELETE', `/accounts/${args['--account-id']}`),
387→  },
388→  media: {
389→    presign: (args) => apiCall('POST', '/media/presign', {
390→      fileName: args['--filename'],
391→      contentType: args['--content-type'],
392→    }),
393→  },
394→  posts: {
395→    create: (args) => {
396→      const body = {
397→        accountIds: JSON.parse(args['--accounts'] || '[]'),
398→        text: args['--text'] || '',
399→      };
400→      if (args['--media']) body.mediaItems = JSON.parse(args['--media']);
401→      if (args['--schedule']) body.scheduledAt = args['--schedule'];
402→      if (args['--draft']) body.draft = true;
403→      if (!args['--draft'] && !args['--schedule']) body.publishNow = true;
404→      if (args['--platform-options']) {
405→        body.platformOptions = JSON.parse(args['--platform-options']);
406→      }
407→      return apiCall('POST', '/posts', body);
408→    },
409→    list: (args) => {
410→      const params = new URLSearchParams();
411→      if (args['--status']) params.set('status', args['--status']);
412→      if (args['--profile']) params.set('profileId', args['--profile']);
413→      if (args['--limit']) params.set('limit', args['--limit']);
414→      const qs = params.toString();
415→      return apiCall('GET', `/posts${qs ? `?${qs}` : ''}`);
416→    },
417→    status: (args) => apiCall('GET', `/posts/${args['--post-id']}`),
418→    retry: (args) => apiCall('POST', `/posts/${args['--post-id']}/retry`),
419→  },
420→  analytics: {
421→    get: (args) => {
422→      const params = new URLSearchParams();
423→      if (args['--post-id']) params.set('postId', args['--post-id']);
424→      if (args['--account-id']) params.set('accountId', args['--account-id']);
425→      if (args['--date-range']) params.set('dateRange', args['--date-range']);
426→      return apiCall('GET', `/analytics?${params.toString()}`);
427→    },
428→  },
429→  queue: {
430→    list: (args) => apiCall('GET', `/queue${args['--profile'] ? `?profileId=${args['--profile']}` : ''}`),
431→    add: (args) => apiCall('POST', '/queue', {
432→      profileId: args['--profile'],
433→      day: args['--day'],
434→      time: args['--time'],
435→    }),
436→    remove: (args) => apiCall('DELETE', `/queue/${args['--slot-id']}`),
437→  },
438→  webhooks: {
439→    get: () => apiCall('GET', '/webhooks'),
440→    set: (args) => apiCall('POST', '/webhooks', {
441→      url: args['--url'],
442→      signingSecret: args['--secret'],
443→    }),
444→  },
445→};
446→
447→// --- Diagnostic Mode ---
448→
449→async function runDiagnostic() {
450→  const key = getApiKey();
451→  console.log(JSON.stringify({ key: maskKey(key), status: 'checking...' }));
452→  try {
453→    const profiles = await commands.profiles.list();
454→    const accounts = await commands.accounts.list({});
455→    console.log(JSON.stringify({
456→      status: 'ok',
457→      key: maskKey(key),
458→      profiles: profiles,
459→      accounts: accounts,
460→    }, null, 2));
461→  } catch (err) {
462→    console.error(JSON.stringify({ status: 'error', code: err.code, message: err.message }));
463→    process.exit(1);
464→  }
465→}
466→
467→// --- Validate-Only Mode ---
468→
469→async function runValidateOnly() {
470→  const key = getApiKey();
471→  try {
472→    await commands.profiles.list();
473→    console.log(JSON.stringify({ status: 'ok', key: maskKey(key) }));
474→  } catch (err) {
475→    console.error(JSON.stringify({ status: 'error', code: err.code }));
476→    process.exit(1);
477→  }
478→}
479→
480→// --- Argument Parsing ---
481→
482→function parseArgs(argv) {
483→  const args = {};
484→  const positional = [];
485→  for (const arg of argv) {
486→    if (arg.startsWith('--')) {
487→      const eqIndex = arg.indexOf('=');
488→      if (eqIndex !== -1) {
489→        args[arg.slice(0, eqIndex)] = arg.slice(eqIndex + 1);
490→      } else {
491→        args[arg] = true;
492→      }
493→    } else {
494→      positional.push(arg);
495→    }
496→  }
497→  return { args, positional };
498→}
499→
500→// --- Main ---

